112→// extractTable queries a single table and returns its column names and rows.
113→// When geoJSON is true, geometry columns are wrapped with ST_AsGeoJSON to
114→// produce portable GeoJSON text instead of binary WKB.
115→func extractTable(ctx context.Context, conn *pgx.Conn, schema, table string, filtered bool, unitIDs []string, geoJSON bool) (tableData, error) {
116→	qualifiedName := fmt.Sprintf("%s.%s", schema, table)
117→
118→	// When geoJSON mode is requested, we need to discover geometry columns
119→	// and replace them with ST_AsGeoJSON() calls in the SELECT list.
120→	selectExpr := "*"
121→	if geoJSON {
122→		cols, err := buildGeoJSONSelect(ctx, conn, schema, table)
123→		if err != nil {
124→			return tableData{}, err
125→		}
126→		if cols != "" {
127→			selectExpr = cols
128→		}
129→	}
130→
131→	var query string
132→	var rows pgx.Rows
133→	var err error
134→
135→	if filtered {
136→		query = fmt.Sprintf("SELECT %s FROM %s WHERE unit_id = ANY($1) ORDER BY 1", selectExpr, qualifiedName)
137→		rows, err = conn.Query(ctx, query, unitIDs)
138→	} else {
139→		query = fmt.Sprintf("SELECT %s FROM %s ORDER BY 1", selectExpr, qualifiedName)
140→		rows, err = conn.Query(ctx, query)
141→	}
142→	if err != nil {
143→		return tableData{}, fmt.Errorf("samplesql: query %s: %w", qualifiedName, err)
144→	}
145→	defer rows.Close()
146→
147→	fieldDescs := rows.FieldDescriptions()
148→	columns := make([]string, len(fieldDescs))
149→	for i, fd := range fieldDescs {
150→		columns[i] = fd.Name
151→	}
152→
153→	var dataRows [][]any
154→	for rows.Next() {
155→		values, err := rows.Values()
156→		if err != nil {
157→			return tableData{}, fmt.Errorf("samplesql: scan %s: %w", qualifiedName, err)
158→		}
159→		dataRows = append(dataRows, values)
160→	}
161→	if err := rows.Err(); err != nil {
162→		return tableData{}, fmt.Errorf("samplesql: iterate %s: %w", qualifiedName, err)
163→	}
164→
165→	return tableData{
166→		Schema:  schema,
167→		Table:   table,
168→		Columns: columns,
169→		Rows:    dataRows,
170→	}, nil
171→}
172→
173→// buildGeoJSONSelect queries information_schema to find geometry/geography
174→// columns and builds a SELECT list that wraps them with ST_AsGeoJSON().
175→// Returns "" if no geometry columns are found (caller should use SELECT *).
176→func buildGeoJSONSelect(ctx context.Context, conn *pgx.Conn, schema, table string) (string, error) {
177→	rows, err := conn.Query(ctx,
178→		`SELECT column_name, udt_name
179→		 FROM information_schema.columns
180→		 WHERE table_schema = $1 AND table_name = $2
181→		 ORDER BY ordinal_position`, schema, table)
182→	if err != nil {
183→		return "", fmt.Errorf("samplesql: schema query %s.%s: %w", schema, table, err)
184→	}
185→	defer rows.Close()
186→
187→	var parts []string
188→	hasGeo := false
189→	for rows.Next() {
190→		var colName, udtName string
191→		if err := rows.Scan(&colName, &udtName); err != nil {
192→			return "", fmt.Errorf("samplesql: schema scan: %w", err)
193→		}
194→		if udtName == "geometry" || udtName == "geography" {
195→			parts = append(parts, fmt.Sprintf("ST_AsGeoJSON(%s)::jsonb AS %s", colName, colName))
196→			hasGeo = true
197→		} else {
198→			parts = append(parts, colName)
199→		}
200→	}
201→	if err := rows.Err(); err != nil {
202→		return "", fmt.Errorf("samplesql: schema iterate: %w", err)
203→	}
204→
205→	if !hasGeo {
206→		return "", nil
207→	}
208→
209→	result := ""
210→	for i, p := range parts {
211→		if i > 0 {
212→			result += ", "
213→		}
214→		result += p
215→	}
216→	return result, nil
217→}
